"use client"

import * as React from "react"
import {
  ProgressBar as ProgressPrimitive,
  type ProgressBarProps as ProgressPrimitiveProps,
} from "react-aria-components"

import { cn } from "@/registry/react-aria-mira/lib/utils"

function Progress({
  className,
  label,
  showValueLabel = false,
  ...props
}: Omit<ProgressPrimitiveProps, "children" | "className"> & {
  className?: string
  label?: React.ReactNode
  showValueLabel?: boolean
}) {
  return (
    <ProgressPrimitive
      data-slot="progress"
      className={cn("flex flex-wrap gap-3", className)}
      {...props}
    >
      {({ percentage, valueText, isIndeterminate }) => (
        <>
          {label ? (
            <span
              className={cn("text-xs/relaxed font-medium")}
              data-slot="progress-label"
            >
              {label}
            </span>
          ) : null}
          {showValueLabel ? (
            <span
              className={cn(
                "ml-auto text-xs/relaxed text-muted-foreground tabular-nums"
              )}
              data-slot="progress-value"
            >
              {valueText}
            </span>
          ) : null}
          <span
            className={cn(
              "relative flex h-1 w-full items-center overflow-x-hidden rounded-md bg-muted"
            )}
            data-slot="progress-track"
          >
            <span
              data-slot="progress-indicator"
              className={cn("h-full bg-primary transition-all")}
              style={{ width: `${isIndeterminate ? 100 : percentage}%` }}
            />
          </span>
        </>
      )}
    </ProgressPrimitive>
  )
}

export { Progress }
